public void updateBlocks() {
    for (int i = 0; i < CHUNK_SIZE_CUBED; i++) {
        Block b = blocks[i];
        if (b != null) {
            int n_x = i - 1;
            int p_x = i + 1;
            int n_y = i - CHUNK_SIZE;
            int p_y = i + CHUNK_SIZE;
            int n_z = i - CHUNK_SIZE_SQUARED;
            int p_z = i + CHUNK_SIZE_SQUARED;

            if (b.x - 1 < 0) {
                //TODO: check neighbor chunk
                b.lt = false;
            } else {
                Block bl = blocks[n_x];
                if (bl == null)
                    b.lt = true;
                else
                    b.lt = false;
            }

            if (b.y - 1 < 0) {
                //TODO: check neighbor chunk
                b.bt = false;
            } else {
                Block bl = blocks[n_y];
                if (bl == null)
                    b.bt = true;
                else
                    b.bt = false;
            }

            if (b.z - 1 < 0) {
                //TODO: check neighbor chunk
                b.ft = false;
            } else {
                Block bl = blocks[n_z];
                if (bl == null)
                    b.ft = true;
                else
                    b.ft = false;
            }

            if (b.x + 1 >= CHUNK_SIZE) {
                //TODO: check neighbor chunk
                b.rt = false;
            } else {
                Block bl = blocks[p_x];
                if (bl == null)
                    b.rt = true;
                else
                    b.rt = false;
            }

            if (b.y + 1 >= CHUNK_SIZE) {
                //TODO: check neighbor chunk
                b.tp = false;
            } else {
                Block bl = blocks[p_y];
                if (bl == null)
                    b.tp = true;
                else
