public class NoiseExample {
    public static void main(String[] args) {
        // We will use the noise function to generate a texture map for a sphere.
        int size = 256; // size of the grid in pixels
        double scale = 0.1; // Scale factor for the noise
        double offsetX = -0.5; // X offset for the noise
        double offsetY = -0.5; // Y offset for the noise
        int[] texture = new int[size * size];
        for(int y = 0; y < size; y++) {
            for(int x = 0; x < size; x++) {
                // Calculate the coordinates (x,y) on the sphere.
                double radius = Math.sqrt(Math.pow(x - offsetX, 2) + Math.pow(y - offsetY, 2));
                double angle = Math.PI * ((double) x / size);
                double noiseValue = noise(radius, scale, angle);
                // Calculate the color for this pixel as a red value based on the noise.
                int red = (int) (noiseValue * 255.0);
                texture[y * size + x] = (red << 16) | (red << 8) | 0xFF;
            }
        }
    }
}

